static vector<bool> noans(1000);
int NBBot::playGame(NBGame &game, bool dispTurn, bool dispRes)
{
  fill(noans.begin(), noans.end(), false);
  for (auto b : board)
  {
    if (noans[b[0] * 100 + b[1] * 10 + b[2]]) continue;
    game.playTurn(b[0], b[1], b[2]);
    DISPTURN;
    if (game.getStrike() == 3)
    {
      DISPRES;
      return game.getTurn();
    }
    for (int i = 1; i < 10; i++)
    {
      for (int j = 1; j < 10; j++)
      {
        if (i == j) continue;
        for (int k = 1; k < 10; k++)
        {
          if (k == i || k == j) continue;
          if (noans[i * 100 + j * 10 + k]) continue;

          int st = 0, ba = 0;
          if (i == b[0]) st++;
          else if (i == b[1] || i == b[2]) ba++;
          if (j == b[1]) st++;
          else if (j == b[0] || j == b[2]) ba++;
          if (k == b[2]) st++;
          else if (k == b[0] || k == b[1]) ba++;

          if (game.getStrike() != st || game.getBall() != ba)
            noans[i * 100 + j * 10 + k] = true;
        }
      }
    }
  }

  cout << "ERROR OCCURED\n";
  return -1;
}